Rule.Source:
  import sailpoint.object.CertificationDefinition;
  import sailpoint.object.CertificationEntity;
  import sailpoint.object.CertificationItem;
  import sailpoint.object.Identity;
  import sailpoint.object.Link;
  import sailpoint.object.AuditEvent;
  import sailpoint.object.Certification;
  import sailpoint.object.Attributes;
  import sailpoint.object.EntitlementSnapshot;
  import sailpoint.object.Filter;
  import sailpoint.object.QueryOptions;
	import sailpoint.object.Application;

  import sailpoint.tools.Util;
  import sailpoint.web.messages.MessageKeys;
  import sailpoint.api.SailPointContext;
  import sailpoint.api.SailPointFactory;
  import sailpoint.api.IdentityService;
  import sailpoint.object.AbstractCertificationItem.Status;
  import sailpoint.object.CertificationAction.Status;
  import sailpoint.server.Auditor;
  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;


  Log logger = LogFactory.getLog("org.ascension.sailpoint.rules.remediationAudit");
  logger.debug("Starting Revocation Audit Rule");
  if(certification == null)
    return;
  String auditAction;
  String certificationName = certification.getName();
  String applicationName;
  String certificationOwner;
  String certifierEmployeeId;
  String certifierEmail;
  String certifierDisplayName;
  String certifierPhone;
  String targetUserId;
  String targetUserDisplayName;
  String targetUserSAMAccName;
  String entitlementName;
  String entitlementValue;
  String actionStatus;
  String targetUserMinistry = "";
  String certifierMinistry = "";

  String certDefinitionId = certification.getCertificationDefinitionId();
  CertificationDefinition certDefinition = null;
  if(Util.isNotNullOrEmpty(certDefinitionId))
    certDefinition = context.getObjectById(CertificationDefinition.class, certDefinitionId);
  if(certDefinition != null)
    certificationOwner = certDefinition.getCertificationOwner();
  List certifiers = certification.getCertifiers();
  String singleCertifier = "";
  if(certifiers != null && !certifiers.isEmpty())
    singleCertifier = certifiers.get(0);
  Identity certifierObject = null;
  if(Util.isNotNullOrEmpty(singleCertifier))
    certifierObject = context.getObjectByName(Identity.class, singleCertifier);
  if(certifierObject != null)
  {
    certifierEmployeeId = certifierObject.getAttribute("employeeId");
    certifierEmail = certifierObject.getAttribute("email");
    certifierDisplayName = certifierObject.getAttribute("displayName");
    certifierMinistry = certifierObject.getAttribute("ministry");
  }
  Application app = context.getObjectByName(Application.class, "DB-Peoplesoft-HCM-Primary");
  if(app != null && certifierObject != null)
  {
    IdentityService idenService = new IdentityService(context);
    List authLinks = idenService.getLinks(certifierObject, app);
    if(authLinks != null && !authLinks.isEmpty())
    {
      Link authLink = authLinks.get(0);
      if(authLink != null)
        certifierPhone = authLink.getAttribute("PHONE");
    }
  }


  List certEntity = certification.getEntities(); 
  if(certEntity == null || certEntity.isEmpty())
    return;
  for (CertificationEntity certen : certEntity)
  {
    targetUserId = certen.getIdentity();
    if(Util.isNotNullOrEmpty(targetUserId))
    {
      Identity targetObject = context.getObjectByName(Identity.class, targetUserId);
      if(null != targetObject)
      {
        targetUserDisplayName = targetObject.getAttribute("displayName");
        targetUserSAMAccName = targetObject.getAttribute("samAccountName");
        targetUserMinistry = certifierObject.getAttribute("ministry");
      }
    }
    List certItems = certen.getItems(); 
    logger.debug("CertificationItems: " +certItems);
    if(certItems == null || certItems.isEmpty())
      continue;
    for (CertificationItem certItem : certItems)
    {
      if(null == certItem)
        continue;
      logger.debug("certItem: " +certItem.toXml());
      List appNames = certItem.getApplicationNames();
      if(appNames != null && !appNames.isEmpty())	
        applicationName = appNames.get(0);
      EntitlementSnapshot entShot = certItem.getExceptionEntitlements();
      if(entShot != null)
      {
        entitlementName = entShot.getAttributeName();
        entitlementValue = entShot.getAttributeValue();
      }


      if (certItem.getAction() != null)
        actionStatus = certItem.getAction().getStatus().toString();
      else
        actionStatus = certItem.getSummaryStatus().getMessageKey(); 


      if(certification.getPhase() != null && "Active".equalsIgnoreCase(certification.getPhase().toString()))  
        auditAction="HFMCertificationCreation";
      else
      {
        QueryOptions openAudtquery = new QueryOptions();
        auditAction="HFMCertificationEnding";
        context.removeObjects(AuditEvent.class, openAudtquery.addFilter(Filter.and(Filter.eq("action", "HFMCertificationCreation"), Filter.eq("source", certificationName))));
        context.commitTransaction();
      }


      if(Auditor.isEnabled(auditAction))
      {
        AuditEvent event = new AuditEvent();
        event.setAction(auditAction);
        event.setSource(certificationName);
        event.setApplication(applicationName);
        Attributes attributes = new Attributes();
        attributes.put("certificationOwner",certificationOwner); 
        attributes.put("certifierEmployeeId",certifierEmployeeId);        
        attributes.put("certifierEmail",certifierEmail);
        attributes.put("certifierDisplayName",certifierDisplayName);
        attributes.put("certifierPhone",certifierPhone);
        attributes.put("certifierMinistry",certifierMinistry);
        attributes.put("targetUserId",targetUserId);
        attributes.put("targetUserDisplayName",targetUserDisplayName);
        attributes.put("targetUserSAMAccName",targetUserSAMAccName);
        attributes.put("targetUserMinistry",targetUserMinistry);
        attributes.put("entitlementName",entitlementName);
        attributes.put("entitlementValue",entitlementValue);
        attributes.put("actionStatus",actionStatus);
        event.setAttributes(attributes);
        logger.debug("Get Attributes: " +event.getAttributes());
        Auditor.log(event);
        context.saveObject(event);
        context.commitTransaction();
      }
    }
  }
  logger.debug("Ending Revocation Audit Rule");
